"""
MKT Original Language Commentary — Psalms chapters 96–102 (84 verses)
Run: python3 scripts/zc-original-psalms-96-102.py

Key decisions in this range:
- Ps 96: shîr ḥādāsh (new song) connects to Isa 42:10; Rev 5:9; ʾĕlîlîm (idols) as
  wordplay on ʾal (nothing); bĕhadrat-qōdesh (splendor of holiness, v9) — the
  sanctuary's paradox of terrifying beauty; YHWH mālāk (v10) as the enthronement
  formula; coming-to-judge (v13) as the eschatological climax
- Ps 97: ʿānān waʿărāpel (clouds and thick darkness, v2) — Sinai theophany language;
  mountains melting like wax (v5) — Mic 1:4; the triple shame of idol-worshippers;
  ʾôr-zārûaʿ laṣṣaddîq (light sown for the righteous, v11) as eschatological promise
- Ps 98: yāmîn + zĕrôaʿ qōdshô (right hand + holy arm, v1) as warrior-rescue;
  ḥesed wĕʾĕmûnāh (v3) as the covenant pair; nĕhārôt yimḥăʾû-khāp (rivers clap
  hands, v8) — the widening of creation's chorus; closing judge-theophany parallel to Ps 96
- Ps 99: triple qādôsh hûʾ (vv3/5/9) as the psalm's structural spine; ʿōz+mishpāṭ
  (mighty king loves justice, v4); Moses/Aaron/Samuel as intercessory triad (v6);
  God who both forgave and held accountable (v8) — the unresolved tension
- Ps 100: mizmôr lĕtôdāh — the only psalm with this unique superscription; the
  Qere/Ketiv variant at v3 (wĕlô/wĕlōʾ, "we are his" vs "not we ourselves"); the
  fivefold imperative structure; tripartite conclusion (good/ḥesed/ʾĕmûnāh, v5)
- Ps 101: David's royal manifesto of court ethics; mātay tābôʾ ʾêlay (v2, "O when
  will you come?") as the psalm's hidden cry; bĕliyaʿal (vile/worthlessness, v3);
  labĕqārîm (each morning, v8) as the king's judicial rhythm
- Ps 102: unique narrative superscription (only psalm with one); the individual lament
  folding into cosmic hope; pelican + solitary bird as the psalm's desolation images;
  vv25-27 cited in Heb 1:10-12 and addressed by the Father to the Son — the same
  eternal Creator who laid creation's foundations
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 96-102 — the enthronement cluster (96, 97, 98, 99),
#   the thanksgiving psalm (100), David's royal court manifesto (101), and the great
#   individual lament with embedded creation hymn (102), including the Heb 1:10-12
#   citation of Ps 102:25-27 applied to the pre-incarnate Son.
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(96,103)])"

PSALMS = {
  "96": {
    "1": '<p><strong>שִׁירוּ לַיהוָה שִׁיר חָדָשׁ שִׁירוּ לַיהוָה כָּל-הָאָרֶץ</strong> (<em>shîrû layhwāh shîr ḥādāsh shîrû layhwāh kol-hāʾāreṣ</em>, "Sing to the LORD a new song; sing to the LORD, all the earth!") — <em>shîr ḥādāsh</em>: the new song (Ps 33:3; 40:3; 98:1; 144:9; 149:1; Isa 42:10; Rev 5:9 — the eschatological hymn that only the redeemed can sing). The repetition of the imperative <em>shîrû</em> is not redundant: the first is the command, the second extends the address from Israel to <em>kol-hāʾāreṣ</em> (all the earth — the universal scope that is the driving theme of Ps 96). Psalm 96 is nearly identical to 1 Chronicles 16:23-33 (the song David appointed when the ark arrived in Jerusalem) — the enthronement psalm given a historical anchor in the Davidic establishment of worship.</p>',
    "2": '<p><strong>שִׁירוּ לַיהוָה בָּרְכוּ שְׁמוֹ בַּשְּׂרוּ מִיּוֹם-לְיוֹם יְשׁוּעָתוֹ</strong> (<em>shîrû layhwāh bārĕkhû shĕmô basshĕrû miyyôm-lĕyôm yĕshûʿātô</em>, "Sing to the LORD, bless his name; announce his salvation from day to day!") — <em>bassar</em> (piel: to announce good news — the same verb behind <em>mĕbaśśêr</em> in Isa 52:7: "how beautiful the feet of one who announces good news"; the Greek <em>εὐαγγελίζεσθαι</em>/evangelism). <em>Miyyôm-lĕyôm</em>: day to day (the continuous proclamation — not a single announcement but a daily rhythm of gospel-bearing). <em>Yĕshûʿāh</em>: salvation (the name of Joshua/Jesus: Num 13:16; Matt 1:21).</p>',
    "3": '<p><strong>סַפְּרוּ בַגּוֹיִם כְּבוֹדוֹ בְּכָל-הָעַמִּים נִפְלְאֹתָיו</strong> (<em>sappĕrû baggôyim kĕbôdô bĕkhol-hāʿammîm nipĕlĕʾōtāyw</em>, "Announce his glory among the nations and his wondrous deeds among all peoples!") — <em>sappĕrû</em> (piel: to recount, to declare in full — not a brief mention but a thorough narration). <em>Kĕbôdô</em>: his glory (the <em>kābôd YHWH</em> — the weighty, heavy reality of his divine presence and character). <em>Nipĕlĕʾōtāyw</em>: his wonders (from <em>pālāʾ</em>: extraordinary acts that exceed human comprehension — Exod 3:20; 15:11; Ps 77:11). The missionaries\'s mandate: not opinions about God but the narration of his actual acts.</p>',
    "4": '<p><strong>כִּי גָדוֹל יְהוָה וּמְהֻלָּל מְאֹד נוֹרָא הוּא עַל-כָּל-אֱלֹהִים</strong> (<em>kî gādôl yĕhwāh ûmĕhullāl mĕʾōd nôrāʾ hûʾ ʿal-kol-ʾĕlōhîm</em>, "For the LORD is great and most worthy of praise; he is to be held in awe above every other god!") — <em>gādôl</em>: great in every superlative (size, power, goodness — Ps 145:3). <em>Mĕhullāl mĕʾōd</em>: greatly to be praised (<em>hallel</em>: the root of Hallelujah). <em>Nôrāʾ</em>: awesome/terrifying (from <em>yārēʾ</em>: to fear — the word for awe-inspiring). <em>ʿAl-kol-ʾĕlōhîm</em>: above all gods — the comparative claim that relativizes all rivals without denying their existence as spiritual realities (Ps 82:1; 1 Cor 8:5-6).</p>',
    "5": '<p><strong>כִּי כָּל-אֱלֹהֵי הָעַמִּים אֱלִילִים</strong> (<em>kî kol-ʾĕlōhê hāʿammîm ʾĕlîlîm</em>, "For all the gods of the nations are <em>ʾĕlîlîm</em>!") — <em>ʾĕlîlîm</em>: a pointed theological term — "worthless things, nothings" (from the root related to <em>ʾal</em>: no/not; the word plays on <em>ʾĕlōhîm</em> but inverts it). Isa 2:8,18,20; 10:10; 19:3 use the same word. The contrast is cosmic: all rival "gods" are zeroes; YHWH made the heavens. <strong>וַיהוָה שָׁמַיִם עָשָׂה</strong> (<em>wayhwāh shāmayim ʿāśāh</em>, "but the LORD made the heavens") — the creator vs the creature: idols are things made by human hands (Ps 115:4-8); YHWH is the Maker of the sky itself.</p>',
    "6": '<p><strong>הוֹד-וְהָדָר לְפָנָיו עֹז וְתִפְאֶרֶת בְּמִקְדָּשׁוֹ</strong> (<em>hôd-wĕhādār lĕpānāyw ʿōz wĕtipʾeret bĕmiqdāshô</em>, "Honor and majesty are before him; strength and beauty fill his sanctuary!") — two paired couplets: <em>hôd wĕhādār</em> (honor and majesty — the royal radiance of the divine presence; Ps 104:1; 111:3) and <em>ʿōz wĕtipʾeret</em> (strength and beauty/splendor — the two-fold character of the sanctuary). <em>Lĕpānāyw</em>: before him (in his very presence these qualities exist as attendants). <em>Bĕmiqdāshô</em>: in his sanctuary — bringing the cosmic divine character into the concrete worship space.</p>',
    "7": '<p><strong>הָבוּ לַיהוָה מִשְׁפְּחוֹת עַמִּים הָבוּ לַיהוָה כָּבוֹד וָעֹז</strong> (<em>hābû layhwāh mishpĕḥôt ʿammîm hābû layhwāh kābôd wāʿōz</em>, "Give to the LORD, O families of the nations — give to the LORD glory and strength!") — <em>hābû</em>: give!/ascribe! (imperative of <em>yāhab</em>: to give — Ps 29:1-2 uses the same structure for the heavenly beings). <em>Mishpĕḥôt ʿammîm</em>: the families/clans of the peoples — a more intimate, household-level word for nations than <em>gôyim</em>, implying the universal call extends to every family unit. The glory they ascribe already belongs to God; they are acknowledging what is true, not granting something new.</p>',
    "8": '<p><strong>הָבוּ לַיהוָה כְּבוֹד שְׁמוֹ שְׂאוּ-מִנְחָה וּבֹאוּ לְחַצְרוֹתָיו</strong> (<em>hābû layhwāh kĕbôd shĕmô śĕʾû-minḥāh ûbōʾû lĕḥaṣrōtāyw</em>, "Give to the LORD the honor his name deserves; bring your offering and come into his courts!") — <em>kĕbôd shĕmô</em>: "the honor/glory of his name" — giving the name its due weight (<em>kābôd</em>: heaviness, weightiness). <em>Minḥāh</em>: the grain offering (Lev 2) or simply "gift/tribute" — the tangible physical expression of honor. <em>Ḥaṣrōtāyw</em>: his courts (the outer courts of the sanctuary open to all who would approach). The nations are invited into the temple courts — Isa 56:7: "my house shall be called a house of prayer for all peoples."</p>',
    "9": '<p><strong>הִשְׁתַּחֲווּ לַיהוָה בְּהַדְרַת-קֹדֶשׁ חִילוּ מִפָּנָיו כָּל-הָאָרֶץ</strong> (<em>hishtaḥăwû layhwāh bĕhadrat-qōdesh ḥîlû mippānāyw kol-hāʾāreṣ</em>, "Worship the LORD in the splendor of holiness; tremble before him, all the earth!") — <em>bĕhadrat-qōdesh</em>: "in the splendor of holiness" or "in holy array/adornment" — the ambiguity covers both the worshiper\'s approach (dressed in the beauty of consecrated life) and the sanctuary\'s character (radiant with the holiness of the divine presence). <em>Ḥîlû</em>: tremble, writhe (the same verb for labor pains — Ps 29:8-9; 77:16 — the earth convulsing in the divine presence). The invitation to draw near and the command to tremble coexist without resolution.</p>',
    "10": '<p><strong>אִמְרוּ בַגּוֹיִם יְהוָה מָלָךְ</strong> (<em>ʾimrû baggôyim yĕhwāh mālāk</em>, "Declare among the nations: \'The LORD reigns!\'") — <em>YHWH mālāk</em>: the enthronement formula (Ps 93:1; 97:1; 99:1) — the proclamation that the cosmic battle has been decided, the true king is on his throne. <strong>אַף-תִּכּוֹן תֵּבֵל בַּל-תִּמּוֹט</strong> (<em>ʾap-tikkôn têbêl bal-timmôṭ</em>, "The world is set firm and cannot be shaken!") — <em>têbêl</em>: the inhabited world (the earth as the place of human civilization). <em>Tikkôn</em>: established, set firm (as opposed to the primordial chaos). <strong>יָדִין עַמִּים בְּמֵישָׁרִים</strong> (<em>yādîn ʿammîm bĕmêshārîm</em>, "He will judge the peoples with equity!") — <em>mêshārîm</em>: equity, what is straight/level (Ps 45:6; 99:4). The proclamation of kingship is simultaneously the promise of justice.</p>',
    "11": '<p><strong>יִשְׂמְחוּ הַשָּׁמַיִם וְתָגֵל הָאָרֶץ יִרְעַם הַיָּם וּמְלֹאוֹ</strong> (<em>yiśmĕḥû hashshāmayim wĕtāgêl hāʾāreṣ yirʿam hayyām ûmĕlōʾô</em>, "Let the heavens rejoice and the earth be glad; let the sea roar with all that fills it!") — the cosmos responds to the enthronement proclamation of v10: heaven above, earth below, and sea between all break into the acclamation. <em>Rāʿam</em>: to thunder, to roar (Ps 77:18 — the roar of the sea-storm as divine theophany). The joy of v11 is not merely emotional — it is creation\'s proper response to its Creator being acknowledged as king.</p>',
    "12": '<p><strong>יַעֲלֹז שָׂדַי וְכָל-אֲשֶׁר-בּוֹ אָז יְרַנְּנוּ כָּל-עֲצֵי-יָעַר</strong> (<em>yaʿălōz śāday wĕkhol-ʾăsher-bô ʾāz yĕrannĕnû kol-ʿăṣê-yāʿar</em>, "Let the fields exult and everything in them! Then all the trees of the forest shall sing for joy!") — <em>ʿālaz</em>: to exult, leap for joy (Ps 68:4; Prov 23:16). The celebration widens from humans (vv1-9) to nations (v10) to sky, earth, sea (v11) to fields and forests (v12): a concentric-ring expansion of the worshipping community. The "then" (<em>ʾāz</em>) in v12 points forward to v13\'s coming — the exultation precedes and anticipates the arrival of the judge.</p>',
    "13": '<p><strong>לִפְנֵי יְהוָה כִּי בָא כִּי בָא לִשְׁפֹּט הָאָרֶץ</strong> (<em>lipnê yĕhwāh kî bāʾ kî bāʾ lishpōṭ hāʾāreṣ</em>, "before the LORD, for he is coming — yes, he is coming — to judge the earth!") — the double <em>kî bāʾ</em> (for he is coming) is liturgical emphasis — the repeated announcement of an imminent, certain arrival. <strong>יִשְׁפֹּט-תֵּבֵל בְּצֶדֶק וְעַמִּים בֶּאֱמוּנָתוֹ</strong> (<em>yishpōṭ-têbêl bĕṣedeq wĕʿammîm beʾĕmûnātô</em>, "He will judge the world in righteousness and the peoples in his faithfulness!") — the closing promise: the coming judge brings not arbitrary power but <em>ṣedeq</em> (righteousness — what is morally right) and <em>ʾĕmûnāh</em> (faithfulness — trustworthy consistency with covenant character). The same closing appears at Ps 98:9. The entire creation chorus of vv11-13 is the response to this promise.</p>',
  },
  "97": {
    "1": '<p><strong>יְהוָה מָלָךְ תָּגֵל הָאָרֶץ יִשְׂמְחוּ אִיִּים רַבִּים</strong> (<em>yĕhwāh mālāk tāgêl hāʾāreṣ yiśmĕḥû ʾiyyîm rabbîm</em>, "The LORD reigns; let the earth rejoice! Let the many coastlands be glad!") — the <em>YHWH mālāk</em> formula (Ps 93:1; 96:10; 99:1) — the enthronement proclamation that the divine warrior has ascended the throne. <em>ʾIyyîm rabbîm</em>: the many islands/coastlands (the most remote inhabited places — Isa 41:1,5; 42:4,10,12 — the distant edges of the known world). The joy of the earth and the distant islands is the proper response to knowing who rules.</p>',
    "2": '<p><strong>עָנָן וַעֲרָפֶל סְבִיבָיו צֶדֶק וּמִשְׁפָּט מְכוֹן כִּסְאוֹ</strong> (<em>ʿānān waʿărāpel sĕbîbāyw ṣedeq ûmishpāṭ mĕkhôn kisʾô</em>, "Clouds and thick darkness surround him; righteousness and justice are the foundation of his throne!") — <em>ʿānān waʿărāpel</em>: cloud and thick darkness — the theophany vocabulary of Sinai (Exod 19:16; 20:21; Deut 4:11; 5:22-23). God\'s hiddenness in the storm is not his absence but his overwhelming presence. The paradox of v2: the concealing darkness and the revealed character (<em>ṣedeq ûmishpāṭ</em>) held together — you cannot see him clearly but you can know what he stands on. <em>Mĕkhôn kisʾô</em>: the foundation/base of his throne (Ps 89:14 — "righteousness and justice are the foundation of your throne").</p>',
    "3": '<p><strong>אֵשׁ לְפָנָיו תֵּלֵךְ וּתְלַהֵט סָבִיב צָרָיו</strong> (<em>ʾêsh lĕpānāyw têlêk ûtĕlahêṭ sābîb ṣārāyw</em>, "Fire goes before him and consumes his enemies all around!") — <em>ʾêsh lĕpānāyw</em>: fire before him — the pillar of fire (Exod 13:21); the divine fire of judgment (Deut 4:24: "your God is a consuming fire"); the fire that went before the ark (Ps 78:14). <em>Lāhaṭ</em> (piel: to blaze fiercely, to scorch — the consuming intensity that leaves nothing). <em>Ṣārāyw</em>: his adversaries (those who are in hostile opposition to the divine king). The fire that guided Israel consumes Israel\'s — and God\'s — enemies.</p>',
    "4": '<p><strong>הֵאִירוּ בְרָקָיו תֵּבֵל רָאֲתָה וַתָּחֵל הָאָרֶץ</strong> (<em>hêʾîrû bĕrāqāyw têbêl rāʾătāh wattāḥel hāʾāreṣ</em>, "His lightnings illuminate the world; the earth sees and shakes with fear!") — <em>bĕrāqāyw</em>: his lightnings (the divine storm-weapons — Ps 18:14: "he shot his arrows and scattered the enemy, with great bolts of lightning he routed them"). <em>Rāʾătāh wattāḥel</em>: saw and writhed (the earth as a creature overcome with the labor-pain spasm of divine presence — Ps 77:16-18). The lightning illuminates the whole world (<em>têbêl</em>) but the sight causes the earth to convulse rather than rejoice.</p>',
    "5": '<p><strong>הָרִים כַּדּוֹנַג נָמַסּוּ מִלִּפְנֵי יְהוָה מִלִּפְנֵי אֲדוֹן כָּל-הָאָרֶץ</strong> (<em>hārîm kaddônag nāmassû milipenê yĕhwāh milipenê ʾădôn kol-hāʾāreṣ</em>, "The mountains melt like wax before the LORD, before the Lord of all the earth!") — <em>kaddônag nāmassû</em>: melted like wax (Mic 1:4: "the mountains will melt under him and the valleys will split apart"; Nah 1:5: "the mountains quake and the hills melt"). Wax is the perfect simile: solid and permanent-seeming, yet responsive to even modest heat. <em>ʾĂdôn kol-hāʾāreṣ</em>: Lord of all the earth — the sovereignty title that encompasses every mountain that melts (used also in Josh 3:11,13 for the ark as the ark of the Lord of all the earth crossing the Jordan).</p>',
    "6": '<p><strong>הִגִּידוּ הַשָּׁמַיִם צִדְקוֹ וְרָאוּ כָל-הָעַמִּים כְּבוֹדוֹ</strong> (<em>higgîdû hashshāmayim ṣidqô wĕrāʾû kol-hāʿammîm kĕbôdô</em>, "The heavens proclaim his righteousness, and all the peoples behold his glory!") — <em>higgîdû hashshāmayim</em>: the heavens tell out (<em>nāgad</em> hiphil: to declare plainly — the same root as Ps 19:1: "the heavens declare the glory of God"). The sky that was illuminated by the divine lightning (v4) becomes the medium of proclamation. <em>Kĕbôdô</em>: his glory (the <em>kābôd</em> that all the peoples witness — the cosmic theophany making God\'s character visible to every nation).</p>',
    "7": '<p><strong>יֵבֹשׁוּ כָּל-עֹבְדֵי פֶסֶל הַמִּתְהַלְלִים בָּאֱלִילִים</strong> (<em>yēbōshû kol-ʿōbĕdê pesel hammithallĕlîm bāʾĕlîlîm</em>, "All who serve carved images are put to shame — those who boast in worthless idols!") — <em>pesel</em>: the carved/graven image (the hand-made idol — Exod 20:4; Deut 5:8; Isa 44:9-20). <em>Hammithallĕlîm</em>: those who boast (<em>hālal</em> hithpael: to boast in, to pride oneself on — the reflexive of praise turned inward toward the idol). <em>Bāʾĕlîlîm</em>: in the worthless nothings (Ps 96:5 — the ʾĕlîlîm, the nothings). <strong>הִשְׁתַּחֲווּ-לוֹ כָּל-אֱלֹהִים</strong> (<em>hishtaḥăwû-lô kol-ʾĕlōhîm</em>, "all gods bow down before him!") — even the spiritual powers behind the idols prostrate themselves before YHWH (Phil 2:10-11).</p>',
    "8": '<p><strong>שָׁמְעָה וַתִּשְׂמַח צִיּוֹן וַתָּגֵלְנָה בְּנוֹת יְהוּדָה לְמַעַן מִשְׁפָּטֶיךָ יְהוָה</strong> (<em>shāmĕʿāh wattismah ṣiyyôn wattāgêlnāh bĕnôt yĕhûdāh lĕmaʿan mishpāṭêkā yĕhwāh</em>, "Zion heard and was glad, and the daughters of Judah rejoiced because of your judgments, O LORD!") — where all the earth trembled and the mountains melted (vv4-5), Zion <em>heard and was glad</em>. The same theophany that terrifies the nations is good news for the covenant people. <em>Bĕnôt yĕhûdāh</em>: the daughters/towns of Judah (the outlying settlements that rejoiced in the capital\'s God — a merismus for all Judah). <em>Mishpāṭêkā</em>: your judgments — the divine decisions that vindicate the righteous.</p>',
    "9": '<p><strong>כִּי-אַתָּה יְהוָה עֶלְיוֹן עַל-כָּל-הָאָרֶץ מְאֹד נַעֲלֵיתָ עַל-כָּל-אֱלֹהִים</strong> (<em>kî-ʾattāh yĕhwāh ʿelyôn ʿal-kol-hāʾāreṣ mĕʾōd naʿălêtā ʿal-kol-ʾĕlōhîm</em>, "For you, LORD, are the Most High over all the earth; you are exalted far above all gods!") — <em>ʿelyôn</em>: Most High (the divine epithet of Gen 14:18-22; Ps 82:6; 83:18; Dan 7:18). <em>Naʿălêtā mĕʾōd</em>: exceedingly exalted (the hithpael/niphal of <em>ʿālāh</em>: to go up — but here in its superlative form: raised up to a degree that exceeds all comparison). This verse grounds the psalm\'s universal joy (v1) and universal judgment (vv6-7): because YHWH is highest above all, his reign brings appropriate joy to his people and shame to idol-worshippers.</p>',
    "10": '<p><strong>אֹהֲבֵי יְהוָה שִׂנְאוּ-רָע שֹׁמֵר נַפְשׁוֹת חֲסִידָיו מִיַּד רְשָׁעִים יַצִּילֵם</strong> (<em>ʾōhăbê yĕhwāh sinʾû-rāʿ shōmêr napshôt ḥăsîdāyw miyyad rĕshāʿîm yaṣṣîlêm</em>, "You who love the LORD, hate evil! He guards the lives of his faithful and rescues them from the power of the wicked!") — <em>ʾōhăbê yĕhwāh sinʾû-rāʿ</em>: "those who love the LORD, hate evil!" — the moral corollary of divine love: you cannot love good without hating its opposite (Ps 45:7; Prov 8:13; Amos 5:15; Rom 12:9). <em>Shōmêr napshôt ḥăsîdāyw</em>: he guards the lives/souls of his faithful ones (the <em>ḥăsîdîm</em> — those in covenant loyalty with God). The protective love of God for his faithful is the motivation for the ethical command.</p>',
    "11": '<p><strong>אוֹר זָרֻעַ לַצַּדִּיק וּלְיִשְׁרֵי-לֵב שִׂמְחָה</strong> (<em>ʾôr zārûaʿ laṣṣaddîq ûlĕyishĕrê-lêb śimḥāh</em>, "Light is sown for the righteous and gladness for the upright in heart!") — <em>ʾôr zārûaʿ</em>: "light sown" — the agricultural metaphor is striking: light is planted like seed in the ground (even though you cannot see it yet, it will sprout). The righteous person\'s light is not fully visible now — it is buried like a seed in the eschatological soil. <em>Yishĕrê-lêb</em>: the upright in heart (those whose inner orientation is straight, not crooked). Gladness (<em>śimḥāh</em>) planted for them — both terms in the future waiting to emerge.</p>',
    "12": '<p><strong>שִׂמְחוּ צַדִּיקִים בַּיהוָה וְהוֹדוּ לְזֵכֶר קָדְשׁוֹ</strong> (<em>śimḥû ṣaddîqîm bayhwāh wĕhôdû lĕzêker qōdshô</em>, "Rejoice in the LORD, you righteous, and give thanks to his holy name!") — the psalm closes by circling back to its opening joy (v1: the earth rejoicing), but now addressing the covenant community directly. <em>Śimḥû bayhwāh</em>: rejoice in the LORD (not merely at benefits, but in the divine person himself — Phil 4:4: "rejoice in the Lord always"). <em>Hôdû lĕzêker qōdshô</em>: give thanks at the remembrance of his holiness — <em>zêker</em>: the memorial, the name-that-is-remembered (Exod 3:15). Gratitude for the holy character of God is the ultimate form of thanksgiving.</p>',
  },
  "98": {
    "1": '<p>Psalm 98 opens without a superscription (only <em>mizmôr</em> — psalm) and parallels Ps 96 closely. <strong>שִׁירוּ לַיהוָה שִׁיר חָדָשׁ כִּי-נִפְלָאוֹת עָשָׂה</strong> (<em>shîrû layhwāh shîr ḥādāsh kî-nipĕlāʾôt ʿāśāh</em>, "Sing to the LORD a new song, for he has done wondrous things!") — the <em>shîr ḥādāsh</em> (new song) of Ps 96:1 returns, but this time with a reason: <em>kî nipĕlāʾôt ʿāśāh</em> (because he has done wonders). The new song is new because the deed it celebrates is new — a fresh act of divine power that old songs could not yet express. <strong>הוֹשִׁיעָה-לּוֹ יְמִינוֹ וּזְרוֹעַ קָדְשׁוֹ</strong> (<em>hôshîʿāh-llô yĕmînô ûzĕrôaʿ qōdshô</em>, "His right hand and his holy arm have won him the victory!") — <em>yāmîn</em>: the right hand (the hand of power and swearing-of-oaths — Isa 41:10); <em>zĕrôaʿ qōdshô</em>: his holy arm (Isa 52:10: "the LORD has bared his holy arm before the eyes of all the nations, and all the ends of the earth shall see the salvation of our God"). The arm and hand are warrior-body imagery for divine rescue accomplished alone.</p>',
    "2": '<p><strong>הוֹדִיעַ יְהוָה יְשׁוּעָתוֹ לְעֵינֵי הַגּוֹיִם גִּלָּה צִדְקָתוֹ</strong> (<em>hôdîaʿ yĕhwāh yĕshûʿātô lĕʿênê haggôyim gillāh ṣidqātô</em>, "The LORD has made his salvation known; he has revealed his righteousness before the nations!") — <em>hôdîaʿ</em> (hiphil: caused to know, made known — a public announcement of what was previously unknown). <em>Yĕshûʿāh</em>: salvation (the noun whose root gives the name Joshua/Jesus). <em>Gillāh ṣidqātô</em>: he has uncovered/revealed his righteousness (as a garment is pulled aside to show what was underneath — Isa 53:1; Paul cites Isa 52:15 in Rom 15:21 for the gospel going to the gentiles). The salvation is both accomplished and publicly displayed.</p>',
    "3": '<p><strong>זָכַר חַסְדּוֹ וֶאֱמוּנָתוֹ לְבֵית יִשְׂרָאֵל</strong> (<em>zākar ḥasdô wĕʾĕmûnātô lĕbêt yiśrāʾêl</em>, "He has remembered his steadfast love and his faithfulness to the house of Israel!") — <em>zākar</em>: to remember with active effect (not merely mental recall but the divine act of bringing something out of suspension — Gen 8:1: "God remembered Noah"; Exod 2:24: "God remembered his covenant with Abraham"). <em>Ḥesed wĕʾĕmûnāh</em>: the covenant pair — steadfast love (the bond of loyalty) and faithfulness (dependable truth). <strong>רָאוּ כָל-אַפְסֵי-אָרֶץ אֵת יְשׁוּעַת אֱלֹהֵינוּ</strong> (<em>rāʾû kol-ʾapsê-ʾāreṣ ʾêt yĕshûaʿ ʾĕlōhênû</em>, "All the ends of the earth have seen the salvation of our God!") — <em>ʾapsê-ʾāreṣ</em>: the ends/extremities of the earth (the uttermost limits — Isa 40:28; 45:22: "turn to me and be saved, all the ends of the earth").</p>',
    "4": '<p><strong>הָרִיעוּ לַיהוָה כָּל-הָאָרֶץ פִּצְחוּ וְרַנְּנוּ וְזַמֵּרוּ</strong> (<em>hārîʿû layhwāh kol-hāʾāreṣ pitsĕḥû wĕrannĕnû wĕzammêrû</em>, "Shout for joy to the LORD, all the earth! Break forth and sing and make music!") — <em>rûaʿ</em> (hiphil: to shout/blast the war-cry of joy); <em>pātsaḥ</em>: to burst out (in song — Isa 14:7; 52:9; 54:1; 55:12: the bursting joy of the redeemed creation); <em>rānan</em>: to ring out; <em>zāmar</em>: to make music with instrument. Four verbs in cascade — the gathering intensity of a crescendo that universal salvation demands.</p>',
    "5": '<p><strong>זַמְּרוּ לַיהוָה בְּכִנּוֹר בְּכִנּוֹר וְקוֹל זִמְרָה</strong> (<em>zammĕrû layhwāh bĕkhinnôr bĕkhinnôr wĕqôl zimrāh</em>, "Sing praises to the LORD with the harp, with the harp and the sound of melody!") — <em>kinnôr</em>: the lyre (David\'s instrument — 1 Sam 16:16,23; Ps 33:2; 144:9). The repetition of "with the harp, with the harp" is emphatic insistence: not a perfunctory accompaniment but the full-throated dedication of the instrument\'s capacities. <em>Qôl zimrāh</em>: the voice of melody/song (the human voice joining the instrument).</p>',
    "6": '<p><strong>בַּחֲצֹצְרוֹת וְקוֹל שׁוֹפָר הָרִיעוּ לִפְנֵי הַמֶּלֶךְ יְהוָה</strong> (<em>baḥăṣōṣĕrôt wĕqôl shôpār hārîʿû lipnê hammelek yĕhwāh</em>, "With trumpets and the blast of the ram\'s horn shout for joy before the King, the LORD!") — <em>ḥăṣōṣĕrôt</em>: the long metal trumpets (silver trumpets made at Moses\'s command — Num 10:1-10: to be blown at feasts, new moons, and before battles); <em>shôpār</em>: the ram\'s horn (blown at Sinai — Exod 19:16,19; Lev 25:9 for the Jubilee; Zech 9:14 for the final battle). The two instruments together cover both the sacral (trumpet) and the ancient convocation signal (ram\'s horn). <em>Hammelek YHWH</em>: before the King YHWH — the shout is a royal acclamation before the enthronement (Ps 97:1).</p>',
    "7": '<p><strong>יִרְעַם הַיָּם וּמְלֹאוֹ תֵּבֵל וְיֹשְׁבֵי בָהּ</strong> (<em>yirʿam hayyām ûmĕlōʾô têbêl wĕyōshĕbê bāh</em>, "Let the sea thunder with all that fills it, the world and all who dwell in it!") — as in Ps 96:11, the sea is commanded to join the acclamation. <em>Rāʿam</em>: to thunder, roar (the word for the sea\'s most powerful voice — Job 37:2,5; Ps 77:18; 104:7). The sea\'s roar which was once the symbol of chaos threatening creation (Ps 93:3-4; 98:7) is here recruited into the royal acclamation of the God who stilled the chaos.</p>',
    "8": '<p><strong>נְהָרוֹת יִמְחֲאוּ-כָף יַחַד הָרִים יְרַנֵּנוּ</strong> (<em>nĕhārôt yimḥăʾû-khāp yaḥad hārîm yĕrannênnû</em>, "Let the rivers clap their hands; let the mountains sing together for joy!") — <em>nĕhārôt yimḥăʾû-khāp</em>: "rivers clap their hands" — a uniquely striking image (rivers have no hands — the metaphor extends personification into the absurd to capture the magnitude of the joy). <em>Māḥāʾ kap</em>: to clap the palm (the gesture of acclaim and joy — 2 Kgs 11:12; Ps 47:1). The mountains singing (<em>yĕrannênnû</em>: ring out, shout) creates a duet: rivers clapping, mountains singing — all creation in full-throated worship.</p>',
    "9": '<p><strong>לִפְנֵי-יְהוָה כִּי בָא לִשְׁפֹּט הָאָרֶץ יִשְׁפֹּט-תֵּבֵל בְּצֶדֶק וְעַמִּים בְּמֵישָׁרִים</strong> (<em>lipnê-yĕhwāh kî bāʾ lishpōṭ hāʾāreṣ yishpōṭ-têbêl bĕṣedeq wĕʿammîm bĕmêshārîm</em>, "before the LORD, for he is coming to judge the earth! He will rule the world in righteousness and the peoples with fairness!") — almost word-for-word Ps 96:13, forming a deliberate doublet: the enthronement cluster of Psalms 93-99 keeps returning to the coming Judge as its goal and ground. <em>Mêshārîm</em>: straightness/equity (from <em>yāshar</em>: straight). The world song of vv7-8 (seas, rivers, mountains) all points here: the judge who comes is the one before whom all creation properly worships.</p>',
  },
  "99": {
    "1": '<p>Psalm 99 is the third psalm to open with <em>YHWH mālāk</em>. <strong>יְהוָה מָלָךְ יִרְגְּזוּ עַמִּים יֹשֵׁב כְּרוּבִים תָּנוּט הָאָרֶץ</strong> (<em>yĕhwāh mālāk yirgĕzû ʿammîm yōshêb kĕrûbîm tānûṭ hāʾāreṣ</em>, "The LORD reigns; let the peoples tremble! He is enthroned above the cherubim; let the earth shake!") — <em>yirgĕzû</em>: to tremble, to be agitated (Ps 77:16,18 — the shaking of the earth before God). <em>Yōshêb kĕrûbîm</em>: the one who sits/is enthroned between the cherubim — the ark-presence formula (1 Sam 4:4; 2 Sam 6:2; Ps 80:1). The cherubim were the golden figures atop the ark over which the divine glory hovered. <em>Tānûṭ hāʾāreṣ</em>: let the earth shake/totter (the same verb for the earth reeling — Ps 46:2-3; Isa 24:20).</p>',
    "2": '<p><strong>יְהוָה בְּצִיּוֹן גָּדוֹל וְרָם הוּא עַל-כָּל-הָעַמִּים</strong> (<em>yĕhwāh bĕṣiyyôn gādôl wĕrām hûʾ ʿal-kol-hāʿammîm</em>, "The LORD is great in Zion; he is raised high above all the peoples!") — the universal kingship (v1: <em>yirgĕzû ʿammîm</em>) grounded in the particular place (Zion): God reigns from Zion over all peoples. <em>Gādôl</em>: great (in all attributes); <em>rām</em>: high/exalted (the spatial metaphor for supremacy — Isa 2:11,17; Ezek 17:24). The movement from Zion-particularity to universal height is characteristic of the enthronement psalms.</p>',
    "3": '<p><strong>יוֹדוּ שִׁמְךָ גָּדוֹל וְנוֹרָא קָדוֹשׁ הוּא</strong> (<em>yôdû shimĕkā gādôl wĕnôrāʾ qādôsh hûʾ</em>, "Let them praise your name — great and awesome! Holy is he!") — the first occurrence of the psalm\'s triple refrain: <em>qādôsh hûʾ</em> ("holy is he" — vv3, 5, 9). Each refrain concludes a section and is the theological hinge on which everything turns. <em>Qādôsh</em>: the holy (the word denoting the absolute otherness of God — his being set apart from all that is creaturely and sinful). The Seraphim\'s cry of Isa 6:3 ("holy, holy, holy is YHWH of hosts") is the heavenly parallel to this triple refrain. <em>Hûʾ</em>: he — the pronoun carries weight: it is <em>this one</em>, the LORD of Zion (v2), who is holy.</p>',
    "4": '<p><strong>וְעֹז מֶלֶךְ מִשְׁפָּט אָהֵב אַתָּה כּוֹנַנְתָּ מֵישָׁרִים</strong> (<em>wĕʿōz melek mishpāṭ ʾāhêb ʾattāh kônantā mêshārîm</em>, "The mighty King loves justice! You have established equity!") — <em>ʿōz melek</em>: the king\'s strength/might (the power that belongs to the king — Ps 29:11; 46:1). <em>Mishpāṭ ʾāhêb</em>: he loves justice — not merely performs it, but loves it (Isa 61:8: "I the LORD love justice"; Mic 6:8). <em>Kônantā mêshārîm</em>: you have established what is level/equitable (<em>kônen</em>: to set up firmly; <em>mêshārîm</em>: equities — Ps 45:6; 98:9). <strong>מִשְׁפָּט וּצְדָקָה בְּיַעֲקֹב אַתָּה עָשִׂיתָ</strong> (<em>mishpāṭ ûṣĕdāqāh bĕyaʿăqōb ʾattāh ʿāśîtā</em>, "justice and righteousness in Jacob you have carried out!") — the universal king\'s work made concrete in Jacob/Israel.</p>',
    "5": '<p><strong>רוֹמְמוּ יְהוָה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לַהֲדֹם רַגְלָיו קָדוֹשׁ הוּא</strong> (<em>rômĕmû yĕhwāh ʾĕlōhênû wĕhishtaḥăwû lahădom raglāyw qādôsh hûʾ</em>, "Exalt the LORD our God and bow down at his footstool — holy is he!") — the second refrain (<em>qādôsh hûʾ</em>). <em>Rômĕmû</em> (polel: to lift up high — exalt to the highest point); <em>hishtaḥăwû</em>: prostrate yourselves (complete bodily submission). <em>Lahădom raglāyw</em>: at his footstool (Isa 66:1: "heaven is my throne and the earth is my footstool"; 1 Chr 28:2: the ark described as God\'s footstool; Ps 110:1: the enemies made a footstool). The posture of prostration at the footstool combines the highest exaltation of God with the lowest position of the worshiper.</p>',
    "6": '<p><strong>מֹשֶׁה וְאַהֲרֹן בְּכֹהֲנָיו וּשְׁמוּאֵל בְּקֹרְאֵי שְׁמוֹ</strong> (<em>mōsheh wĕʾahărōn bĕkhōhănāyw ûshmûʾêl bĕqōrĕʾê shĕmô</em>, "Moses and Aaron were among his priests; Samuel was among those who called on his name!") — a remarkable trio: Moses (the lawgiver and mediator), Aaron (the first high priest), Samuel (the judge who anointed the first two kings). All three are intercessors — those who stand between God and people in the covenant relationship. Samuel was a Levite (1 Chr 6:28,33) though not of the Aaronic line — his association with Moses and Aaron elevates him to the ranks of the great mediators. <strong>קֹרִאים אֶל-יְהוָה וְהוּא יַעֲנֵם</strong> (<em>qōrĕʾîm ʾel-yĕhwāh wĕhûʾ yaʿănêm</em>, "They cried to the LORD and he answered them!") — the intercessors are defined by their prayer-life: crying to God and receiving answer.</p>',
    "7": '<p><strong>בְּעַמּוּד עָנָן יְדַבֵּר אֲלֵיהֶם</strong> (<em>bĕʿammûd ʿānān yĕdabbêr ʾălêhem</em>, "He spoke to them from the pillar of cloud!") — the divine communication medium: the cloud-pillar of the wilderness (Exod 33:9-10: "the pillar of cloud would descend and stand at the entrance of the tent"; Num 12:5: "the LORD came down in the pillar of cloud and stood at the entrance of the tent and called Aaron and Miriam"). <strong>שָׁמְרוּ עֵדֹתָיו וְחֹק נָתַן-לָמוֹ</strong> (<em>shāmĕrû ʿêdōtāyw wĕḥōq nātan-lāmô</em>, "They kept his testimonies and the law he gave them!") — <em>ʿêdōtāyw</em>: his testimonies/decrees (the covenant stipulations); <em>ḥōq</em>: the fixed ordinance. The intercessors were not merely conduits of divine speech but themselves obedient to what was given through them.</p>',
    "8": '<p><strong>יְהוָה אֱלֹהֵינוּ אַתָּה עֲנִיתָם אֵל נֹשֵׂא הָיִיתָ לָהֶם וְנֹקֵם עַל-עֲלִילוֹתָם</strong> (<em>yĕhwāh ʾĕlōhênû ʾattāh ʿănîtām ʾêl nōśêʾ hāyîtā lāhem wĕnōqêm ʿal-ʿălîlôtām</em>, "O LORD our God, you answered them; you were a God who forgave them, yet you punished their offenses!") — the most theologically dense verse of the psalm. <em>Nōśêʾ</em>: one who lifts/forgives (bearing away iniquity — Exod 34:7: "forgiving iniquity and transgression and sin"). <em>Wĕnōqêm ʿal-ʿălîlôtām</em>: "yet punishing/taking vengeance on their offenses" (<em>nāqam</em>: to avenge, punish; <em>ʿălîlāh</em>: deed, practice — usually the negative deeds). The unresolved tension: God both forgave and punished the same intercessors (Aaron at the golden calf — Exod 32; Moses at Meribah — Num 20:12). Forgiveness and accountability coexist without the one erasing the other — neither cheap grace nor pure retribution.</p>',
    "9": '<p><strong>רוֹמְמוּ יְהוָה אֱלֹהֵינוּ וְהִשְׁתַּחֲווּ לְהַר קָדְשׁוֹ כִּי-קָדוֹשׁ יְהוָה אֱלֹהֵינוּ</strong> (<em>rômĕmû yĕhwāh ʾĕlōhênû wĕhishtaḥăwû lĕhar qōdshô kî-qādôsh yĕhwāh ʾĕlōhênû</em>, "Exalt the LORD our God and worship at his holy mountain, for the LORD our God is holy!") — the third and final refrain, now expanded and with a <em>kî</em>-clause giving the reason: <em>because he is holy</em>. The refrain has shifted: v3 "holy is he"; v5 "holy is he"; v9 "holy is the LORD our God" — the final refrain makes explicit what the pronoun had implied. The prostration shifts from "his footstool" (v5) to "his holy mountain" (Zion — Ps 2:6; 15:1; 43:3) — movement toward the culminating place of the divine presence.</p>',
  },
  "100": {
    "1": '<p>Psalm 100 carries the unique superscription <em>mizmôr lĕtôdāh</em> — "a psalm for/of thanksgiving." While many psalms express thanksgiving, this is the only one formally designated as such, likely used with the <em>tôdāh</em> (thanksgiving) offering of Lev 7:12-15. <strong>הָרִיעוּ לַיהוָה כָּל-הָאָרֶץ</strong> (<em>hārîʿû layhwāh kol-hāʾāreṣ</em>, "Shout for joy to the LORD, all the earth!") — <em>rûaʿ</em> (hiphil: to shout the glad war-cry): the same universal call as Ps 98:4. The psalm is a fivefold imperative sequence (vv1-4) followed by a double explanatory couplet (v5), fitting the shape of a procession into the sanctuary.</p>',
    "2": '<p><strong>עִבְדוּ אֶת-יְהוָה בְּשִׂמְחָה בֹּאוּ לְפָנָיו בִּרְנָנָה</strong> (<em>ʿibdû ʾet-yĕhwāh bĕśimḥāh bōʾû lĕpānāyw birnānāh</em>, "Serve the LORD with joy! Come into his presence with singing!") — <em>ʿābad</em>: to serve/work/worship (the word covers both labor-service and divine worship — the same verb for Israel\'s slavery in Egypt and for Israel\'s worship of God in the desert, Exod 4:23: "let my son go so that he may serve me"). Service to God is not grudging obligation but joyful approach (<em>bĕśimḥāh</em>). <em>Birnānāh</em>: with ringing joy (the sound-word for piercing, glad song — Ps 47:1; 98:4).</p>',
    "3": '<p><strong>דְּעוּ כִּי יְהוָה הוּא אֱלֹהִים</strong> (<em>dĕʿû kî yĕhwāh hûʾ ʾĕlōhîm</em>, "Know that the LORD is God!") — <em>yādaʿ</em>: to know (covenant knowledge — not merely intellectual acknowledgment but relational recognition). <em>Yĕhwāh hûʾ ʾĕlōhîm</em>: "YHWH, he is God" — the Elijah formula (1 Kgs 18:39: "the LORD, he is God!" shouted by the people at Carmel). <strong>הוּא עָשָׂנוּ וְלוֹ אֲנַחְנוּ עַמּוֹ וְצֹאן מַרְעִיתוֹ</strong> (<em>hûʾ ʿāśānû wĕlô ʾănaḥnû ʿammô wĕṣōʾn marʿîtô</em>) — the famous textual crux: the Ketiv (written text) reads <em>wĕlōʾ ʾănaḥnû</em> ("and not we ourselves [made us]") while the Qere (read text) is <em>wĕlô ʾănaḥnû</em> ("and we are his"). Both readings are theologically rich and defensible: the Ketiv refutes self-creation (Deut 32:6: "is he not your Father who created you?"); the Qere asserts covenant belonging ("we are his people and the flock of his pasture" — Ps 95:7; 23:1).</p>',
    "4": '<p><strong>בֹּאוּ שְׁעָרָיו בְּתוֹדָה חֲצֵרֹתָיו בִּתְהִלָּה הוֹדוּ-לוֹ בָּרְכוּ שְׁמוֹ</strong> (<em>bōʾû shĕʿārāyw bĕtôdāh ḥăṣêrōtāyw bĕtĕhillāh hôdû-lô bārĕkhû shĕmô</em>, "Enter his gates with thanksgiving and his courts with praise! Thank him and bless his name!") — the processional sequence: gates (<em>shĕʿārîm</em>) → courts (<em>ḥăṣêrôt</em>) → the name (<em>shēm</em>). Each threshold is entered with its appropriate offering: <em>tôdāh</em> (thanksgiving — the verbal and cultic acknowledgment of grace received) at the gates; <em>tĕhillāh</em> (praise — the ongoing song of God\'s character) in the courts. <em>Bārĕkhû shĕmô</em>: bless his name (speak well of his name — the opposite of taking the name in vain).</p>',
    "5": '<p><strong>כִּי-טוֹב יְהוָה לְעוֹלָם חַסְדּוֹ וְעַד-דֹּר וָדֹר אֱמוּנָתוֹ</strong> (<em>kî-ṭôb yĕhwāh lĕʿôlām ḥasdô wĕʿad-dōr wādōr ʾĕmûnātô</em>, "For the LORD is good; his steadfast love endures forever, and his faithfulness lasts to every generation!") — the explanatory <em>kî</em>-clause (because) answers why all the imperatives of vv1-4 are right. Three divine attributes: <em>ṭôb</em> (good — Ps 34:8: "taste and see that the LORD is good"); <em>ḥesed</em> (steadfast love — the covenant faithfulness); <em>ʾĕmûnāh</em> (faithfulness — reliable dependability). <em>Lĕʿôlām</em>: forever; <em>lĕdōr wādōr</em>: to generation and generation (both the unbounded time-scope and the household-transmission of the knowledge of God\'s goodness). This is the Psalm in miniature.</p>',
  },
  "101": {
    "1": '<p>Psalm 101 is David\'s royal ethical manifesto — a king\'s vow about how he will govern his household and court. <strong>חֶסֶד-וּמִשְׁפָּט אָשִׁירָה לְךָ יְהוָה אֲזַמֵּרָה</strong> (<em>ḥesed-ûmishpāṭ ʾāshîrāh lĕkā yĕhwāh ʾăzammêrāh</em>, "I will sing of steadfast love and justice; to you, LORD, I will make music!") — the paired terms that will structure David\'s governance: <em>ḥesed</em> (steadfast love/loyalty — the covenantal commitment that goes beyond mere legal obligation) and <em>mishpāṭ</em> (justice — the right judgment that orders community life). These are Amos 5:24 ("let justice roll down like waters") and Hos 12:7 ("maintain love and justice") in royal self-commitment. The <em>lĕkā YHWH</em> (to you, LORD) indicates that the king\'s ethical manifesto is addressed to God as its audience and source.</p>',
    "2": '<p><strong>אַשְׂכִּילָה בְּדֶרֶךְ תָּמִים מָתַי תָּבוֹא אֵלָי</strong> (<em>ʾaśkîlāh bĕderek tāmîm mātay tābôʾ ʾêlay</em>, "I will conduct myself with wisdom and integrity. O when will you come to me?") — <em>ʾaśkîlāh</em> (hiphil: to act wisely, to have understanding — from <em>śākal</em>: the wisdom of successful moral living). <em>Derek tāmîm</em>: the blameless/whole way (the integrated path of those with no divided loyalties — Ps 15:2; 18:23; 26:1). The sudden interruption <em>mātay tābôʾ ʾêlay</em> (O when will you come to me?) — the psalm\'s hidden lament: all the ethical resolve of vv1-8 is possible only when God is present. Without the divine coming, the manifesto is empty aspiration. <strong>אֶתְהַלֵּךְ בְּתָם-לְבָבִי בְּקֶרֶב בֵּיתִי</strong> (<em>ʾethallêk bĕtom-lĕbābî bĕqereb bêtî</em>, "I will walk with a blameless heart within my own house!") — integrity begins at home, not in public performance.</p>',
    "3": '<p><strong>לֹא-אָשִׁית לְנֶגֶד עֵינַי דְּבַר-בְּלִיַּעַל</strong> (<em>lōʾ-ʾāshît lĕneged ʿênay dĕbar-bĕliyyaʿal</em>, "I will not set anything vile before my eyes!") — <em>bĕliyyaʿal</em>: worthlessness/wickedness (from <em>bĕlî</em>: without, and possibly <em>yaʿal</em>: profit — "that which is without profit"; or a compound meaning "without going up/ascending" — the depth of worthlessness). The visual gate of the heart: the king who controls what he looks at controls the direction of his desires. <strong>עֲשֵׂה-סֵטִים שָׂנֵאתִי לֹא יִדְבַּק-בִּי</strong> (<em>ʿăśêh-sêṭîm śānêʾtî lōʾ yidbaq-bî</em>, "I despise the conduct of those who fall away; it will not cling to me!") — <em>sêṭîm</em>: turnings-aside, deviations (from the straight way — the word for apostasy). <em>Dābaq</em>: to cling/stick fast (Ruth 1:14; Gen 2:24: "a man shall cling to his wife").</p>',
    "4": '<p><strong>לֵבָב עִקֵּשׁ יָסוּר מִמֶּנִּי רָע לֹא אֵדָע</strong> (<em>lêbāb ʿiqqêsh yāsûr mimmenî rāʿ lōʾ ʾêdāʿ</em>, "A crooked heart will depart from me; I will have nothing to do with evil!") — <em>ʿiqqêsh</em>: crooked, perverse (the opposite of <em>yāshar</em>/straight — Prov 2:15; 8:8; Deut 32:5: "a crooked and twisted generation"). <em>Yāsûr mimmenî</em>: will turn aside from me/will depart from me — the crooked heart will not find a home near the king. <em>Rāʿ lōʾ ʾêdāʿ</em>: evil I will not know (experiential knowledge — I will have no experience of, no acquaintance with). The progressive exclusion: nothing vile before the eyes (v3), nothing crooked in the heart (v4).</p>',
    "5": '<p><strong>מְלוֹשְׁנִי בַסֵּתֶר רֵעֵהוּ אֹתוֹ אַצְמִית</strong> (<em>mĕlôshĕnî bassêter rêʿêhû ʾōtô ʾaṣmît</em>, "Whoever slanders his neighbor in secret — him I will silence!") — <em>lāshan</em> (piel: to use the tongue against — to slander, defame); <em>bassêter</em>: in secret (the covert character-assassination that takes advantage of absence). <em>ʾAṣmît</em>: I will cut off, silence (from <em>ṣāmat</em>: to make silent, to destroy — a judicial action by the king). <strong>גְּבַהּ-עֵינַיִם וּרְחַב לֵבָב אֹתוֹ לֹא אוּכַל</strong> (<em>gĕbah-ʿênayim ûrĕḥab lêbāb ʾōtô lōʾ ʾûkhal</em>, "The proud-eyed and the arrogant-hearted — I will not tolerate!") — <em>gĕbah-ʿênayim</em>: high eyes (the look of arrogance — Prov 6:17: "haughty eyes" first on the list of things God hates); <em>rĕḥab lêbāb</em>: broad of heart (the inflated self-importance that needs no correction). The king\'s court will have no room for those who tear down others or build themselves up.</p>',
    "6": '<p><strong>עֵינַי בְּנֶאֱמְנֵי-אֶרֶץ לָשֶׁבֶת עִמָּדִי הֹלֵךְ בְּדֶרֶךְ תָּמִים הוּא יְשָׁרְתֵנִי</strong> (<em>ʿênay bĕneʾĕmnê-ʾāreṣ lāshabet ʿimmādî hōlêk bĕderek tāmîm hûʾ yĕshārĕtênî</em>, "My eyes will be upon the faithful of the land, that they may live with me; whoever walks the blameless way — he will serve me!") — where v5 described exclusion (the slanderer and the arrogant removed), v6 describes positive selection. <em>Neʾĕmnê-ʾāreṣ</em>: the faithful/trustworthy of the land (from <em>ʾāman</em>: to be firm, reliable — the same root as <em>ʾāmên</em>). <em>Hōlêk bĕderek tāmîm</em>: the one who walks the blameless way (the same phrase as v2 — what David commits to for himself, he also requires for those who serve him). The king\'s advisors and servants must reflect his own ethical commitment.</p>',
    "7": '<p><strong>לֹא-יֵשֵׁב בְּקֶרֶב בֵּיתִי עֹשֵׂה רְמִיָּה</strong> (<em>lōʾ-yêshêb bĕqereb bêtî ʿōśêh rĕmiyyāh</em>, "No one who practices deceit will live in my house!") — <em>rĕmiyyāh</em>: deceit, treachery (from <em>rāmāh</em>: to beguile — Jer 48:10; Mic 6:12). The royal household as a zone of integrity: those who practice deceit are excluded from the covenant space of the king\'s house. <strong>דֹּבֵר שְׁקָרִים לֹא-יִכּוֹן לְנֶגֶד עֵינָי</strong> (<em>dōbêr shĕqārîm lōʾ-yikkôn lĕneged ʿênāy</em>, "No one who speaks lies will stand before my eyes!") — <em>shĕqārîm</em>: lies (the plural covering habitual falsehood). <em>Lōʾ yikkôn</em>: will not be established/will not stand firm (the same root as the "firm establishment" of Ps 93:1; 96:10). Truth is the condition of standing before the king.</p>',
    "8": '<p><strong>לַבְּקָרִים אַצְמִית כָּל-רִשְׁעֵי-אָרֶץ לְהַכְרִית מֵעִיר יְהוָה כָּל-פֹּעֲלֵי אָוֶן</strong> (<em>labĕqārîm ʾaṣmît kol-rishĕʿê-ʾāreṣ lĕhakhrit mêʿîr yĕhwāh kol-pōʿălê ʾāwen</em>, "Each morning I will silence all the wicked of the land, cutting off every evildoer from the city of the LORD!") — <em>labĕqārîm</em>: each morning (the king\'s judicial session was in the morning — 2 Sam 15:2: Absalom sat at the gate in the morning; Jer 21:12: "administer justice every morning"). <em>ʾAṣmît</em>: I will cut off/silence (the repeated verb from v5 — the slanders is cut off; the wicked of the land are cut off). <em>Mêʿîr yĕhwāh</em>: from the city of the LORD (Jerusalem as the place of the divine presence — Ps 48:1-2; 87:3). The psalm ends where it began: the king governs his own heart (vv2-4) and his household (vv5-7) so that the entire city of God may be purged of those who corrupt it.</p>',
  },
  "102": {
    "1": '<p>Psalm 102 bears the only full narrative superscription in the Psalter: <strong>תְּפִלָּה לְעָנִי כִי-יַעֲטֹף וְלִפְנֵי יְהוָה יִשְׁפֹּךְ שִׂיחוֹ</strong> (<em>tĕpillāh lĕʿānî kî-yaʿăṭōp wĕlipnê yĕhwāh yishpōk sîḥô</em>, "A prayer of the afflicted man when he faints and pours out his anguish before the LORD"). <em>ʿĀnaṭ</em>: to be faint/overwhelmed (Ps 107:5: the hungry and thirsty who "fainted in distress"; Lam 2:19). <em>Yishpōk sîḥô</em>: pours out his complaint/meditation (<em>shāpak</em>: to pour out — used of water, blood, and (here) of inner speech; <em>sîaḥ</em>: meditation, complaint, inner discourse — Ps 55:2,17; 64:1). <strong>שִׁמְעָה יְהוָה תְּפִלָּתִי וְשַׁוְעָתִי אֵלֶיךָ תָבוֹא</strong> (<em>shimmĕʿāh yĕhwāh tĕpillātî wĕshaʿwātî ʾêlêkā tābôʾ</em>, "Hear my prayer, O LORD; let my cry come to you!") — the initial petition: both <em>tĕpillāh</em> (the structured prayer) and <em>shaʿwāh</em> (the raw cry of distress — Ps 18:6; 22:24).</p>',
    "2": '<p><strong>אַל-תַּסְתֵּר פָּנֶיךָ מִמֶּנִּי בְּיוֹם צַר-לִי הַטֵּה-אֵלַי אָזְנֶךָ בְּיוֹם אֶקְרָא מַהֵר עֲנֵנִי</strong> (<em>ʾal-tastêr pānêkā mimmenî bĕyôm ṣar-lî haṭṭêh-ʾêlay ʾoznĕkā bĕyôm ʾeqrāʾ mahêr ʿănênî</em>, "Do not hide your face from me when I am in trouble! Lean down and listen; answer me quickly when I call!") — <em>haster pānim</em>: the hiding of the divine face (Ps 13:1; 27:9; 88:14 — the covenant abandonment formula, as in Deut 31:17-18). <em>HaṭṬêh ʾoznĕkā</em>: incline your ear (as a person bends to catch a faint sound — Ps 17:6; 31:2; 71:2). <em>Mahêr ʿănênî</em>: quickly answer me — the urgency of the dying man who cannot wait for a leisurely divine response.</p>',
    "3": '<p><strong>כִּי-כָלוּ בְעָשָׁן יָמָי וְעַצְמוֹתַי כְּמוֹקֵד נִחָרוּ</strong> (<em>kî-khālû bĕʿāshān yāmāy wĕʿaṣmôtay kĕmôqêd niḥārû</em>, "For my days are vanishing like smoke, and my bones burn like a blazing hearth!") — <em>kālû bĕʿāshān</em>: consumed in smoke (the days burning away like a fire that produces smoke but no substance — Ps 37:20; Isa 51:6: "the heavens will vanish like smoke"). <em>ʿAṣmôtay kĕmôqêd niḥārû</em>: my bones are scorched like a blazing hearth (<em>môqêd</em>: a burning/fire, a hearth; <em>ḥārar</em>: to scorch, burn up). The simultaneous experience: the life evaporating like smoke above while the bones burn from within — an interior fire consuming the very frame of the person.</p>',
    "4": '<p><strong>הוּכָּה כָעֵשֶׂב וַיִּבַשׁ לִבִּי כִּי-שָׁכַחְתִּי מֵאֲכֹל לַחְמִי</strong> (<em>hûkkāh kāʿêseb wayyibashshô libbî kî-shākhaktî mêʾăkhōl laḥmî</em>, "My heart is struck down like grass and has dried up; I have even forgotten to eat!") — <em>hûkkāh kāʿêseb</em>: struck down like grass (the image of grass cut down and withering in summer heat — Ps 37:2; 90:5-6; Isa 40:6-8: "all flesh is grass"). <em>Shākhaktî mêʾăkhōl laḥmî</em>: I have forgotten to eat bread — the most basic physical need forgotten: the level of suffering that strips appetite. This is the body-soul connection: the heart drying up causes the forgetting of food; the physical and interior devastation are one.</p>',
    "5": '<p><strong>מִקּוֹל אַנְחָתִי דָּבְקָה עַצְמִי לִבְשָׂרִי</strong> (<em>miqqôl ʾanḥātî dābĕqāh ʿaṣmî livsārî</em>, "From the sound of my groaning my bones cling to my skin!") — <em>ʾanḥāh</em>: groaning (the involuntary sound of deep distress — Ezek 21:6: "groan before their eyes, groan bitterly"; Lam 1:22). <em>Dābĕqāh ʿaṣmî livsārî</em>: my bones cling to my flesh — the wasting away of extreme suffering where there is no more flesh between skin and bone (as in Ezek 37:7-8 where the dry bones have no flesh). The progressive physical decay mirrors the inner emptiness of the forsaken.</p>',
    "6": '<p><strong>דָּמִיתִי לִקְאַת מִדְבָּר הָיִיתִי כְּכוֹס חֳרָבוֹת</strong> (<em>dāmîtî liqĕʾat midbār hāyîtî kĕkhôs ḥărābôt</em>, "I am like a desert owl, like an owl haunting the ruins!") — <em>qāʾat</em>: a pelican or desert bird (Lev 11:18; Isa 34:11; Zeph 2:14 — associated with desolate places). The exact species identification is uncertain (pelican, owl, or desert bird generally) but the habitat is clear: <em>midbār</em> (the wilderness/desert — where no community lives) and <em>ḥărābôt</em> (ruins — where community used to live but was destroyed). The sufferer locates himself not in absence of life but in presence of death and desolation.</p>',
    "7": '<p><strong>שָׁקַדְתִּי וָאֶהְיֶה כְּצִפּוֹר בּוֹדֵד עַל-גָּג</strong> (<em>shāqadtî wāʾehyeh kĕṣippôr bôdêd ʿal-gāg</em>, "I cannot sleep; I am like a solitary bird on a rooftop!") — <em>shāqad</em>: to wake, to be wakeful (Jer 1:12; Jer 31:28: God "watching over" his word; but here the wakeful wakefulness of the insomniac). <em>Ṣippôr bôdêd ʿal-gāg</em>: a solitary bird on a rooftop — not part of a flock, not in a nest (where birds belong), but alone on an exposed surface, above the community but not part of it. The image conveys both isolation and exposure: the suffering person is visible but unreachable.</p>',
    "8": '<p><strong>כָּל-הַיּוֹם חֵרְפוּנִי אוֹיְבָי מְהוֹלְלַי בִּי נִשְׁבָּעוּ</strong> (<em>kol-hayyôm ḥêrĕpûnî ʾôyĕbāy mĕhôlĕlay bî nishbāʿû</em>, "My enemies insult me all day long; those who deride me invoke my name as a curse!") — <em>ḥārap</em>: to reproach, taunt, insult (the word used for Goliath\'s taunting of Israel — 1 Sam 17:10,25,26). <em>Mĕhôlĕlāy</em>: those who rave against him/those who mock madly (from <em>hālal</em> in its negative sense: raving, boasting wildly against). <em>Bî nishbāʿû</em>: "they swear by me" (using his name as a byword for cursing — as in Isa 65:15: "you will leave your name as a curse for my chosen ones"). Social suffering compounding physical suffering.</p>',
    "9": '<p><strong>כִּי-אֵפֶר כַּלֶּחֶם אָכָלְתִּי וְשִׁקֻּוַי בִּבְכִי מָסָכְתִּי</strong> (<em>kî-ʾêper kalleḥem ʾākāltî wĕshiqqûway bibkhî māsakhtî</em>, "For I eat ashes instead of bread and mix my tears into my drink!") — <em>ʾêper</em>: ashes (the substance of mourning — Job 2:8; Esther 4:1; Isa 61:3: "beauty instead of ashes"). Ashes instead of bread: the mourner\'s refusal of ordinary sustenance, or the desperate impossibility of eating when in profound grief. <em>Bibkhî māsakhtî</em>: I mix with tears (<em>māsak</em>: to mix wine with water — Ps 75:8; Isa 19:14). Tears as the drink mixed into what would otherwise be water — the bitterness of existence.</p>',
    "10": '<p><strong>מִפְּנֵי-זַעַמְךָ וְקִצְפֶּךָ כִּי נְשָׂאתַנִי וַתַּשְׁלִיכֵנִי</strong> (<em>mippĕnê-zaʿamĕkā wĕqiṣpekā kî nĕśāʾtanî wattashlîkhênî</em>, "because of your fury and wrath; for you have lifted me up only to hurl me down!") — the theological explanation of the suffering: it is the result of the divine wrath (<em>zaʿam</em>: indignation — Ps 38:3; <em>qeṣep</em>: the fury of the divine anger — Num 1:53; Isa 60:10). <em>Nĕśāʾtanî wattashlîkhênî</em>: "you lifted me up and you threw me down" — the double divine action: God first elevated the person and then cast them away (as a wave lifts and crashes — or as Jonah was lifted by the sea and thrown to the fish). The suffering is not random but theologically located in the divine reaction.</p>',
    "11": '<p><strong>יָמַי כְּצֵל נָטוּי וַאֲנִי כָּעֵשֶׂב אִיבָשׁ</strong> (<em>yāmay kĕṣêl nāṭûy waʾănî kāʿêseb ʾîbāsh</em>, "My days are like a fading shadow at evening; I am withering like grass!") — <em>kĕṣêl nāṭûy</em>: like an extended/lengthened shadow (the long shadow of late afternoon that signals the coming end of day — Ps 109:23: "I am gone like a shadow at evening"). <em>Kāʿêseb ʾîbāsh</em>: withering like grass (Isa 40:7: "the grass withers, the flower fades when the breath of the LORD blows on it"). The life is not just ending but the specific mode of ending is evening-shadow (disappearing without remainder) and dry grass (nothing left to burn).</p>',
    "12": '<p><strong>וְאַתָּה יְהוָה לְעוֹלָם תֵּשֵׁב וְזִכְרְךָ לְדֹר וָדֹר</strong> (<em>wĕʾattāh yĕhwāh lĕʿôlām têshêb wĕzikrĕkā lĕdōr wādōr</em>, "But you, LORD, are enthroned forever; your name endures throughout every generation!") — the psalm\'s central hinge: the great "But you" (<em>wĕʾattāh</em>) that stands in absolute contrast to everything in vv3-11. The suffering person\'s days vanish like smoke (v3) and shadow (v11); YHWH sits enthroned forever (<em>lĕʿôlām</em>). The contrast is total: the Psalmist is radically mortal; God is radically permanent. <em>Zikrĕkā lĕdōr wādōr</em>: your name-that-is-remembered generation to generation — the divine name is the covenant identity that outlasts every human generation (Exod 3:15).</p>',
    "13": '<p><strong>אַתָּה תָקוּם תְּרַחֵם צִיּוֹן כִּי-עֵת לְחֶנְנָהּ כִּי-בָא מוֹעֵד</strong> (<em>ʾattāh tāqûm tĕraḥêm ṣiyyôn kî-ʿêt lĕḥennāh kî-bāʾ môʿêd</em>, "You will arise and have mercy on Zion, for the time to show her favor has come — the appointed season is here!") — the confidence built on v12\'s contrast: if YHWH is enthroned forever, then his arising (<em>qûm</em>: the warrior\'s rising from the throne) to act in compassion is certain. <em>ʿÊt lĕḥennāh</em>: the time of her favor (the appointed moment of divine grace). <em>Môʿêd</em>: the appointed season (the word for the festival calendar — Lev 23; the divine appointment is not vague but timed). The Psalmist shifts from individual suffering to national hope in Zion\'s restoration.</p>',
    "14": '<p><strong>כִּי-רָצוּ עֲבָדֶיךָ אֶת-אֲבָנֶיהָ וְאֶת-עֲפָרָהּ יְחֹנֵנוּ</strong> (<em>kî-rāṣû ʿăbādêkā ʾet-ʾăbānêhā wĕʾet-ʿăpārāh yĕḥōnênû</em>, "For your servants hold her very stones dear and take pity even on her dust!") — the reason God will show favor to Zion: his servants (those still faithful) love even the rubble. <em>Rāṣû</em>: to be pleased with, to favor (the covenant acceptance word — Isa 40:2: "her iniquity is pardoned, she has received from the LORD\'s hand double for all her sins"). The servants\' love for the ruins is itself the sign of the covenant relationship that makes restoration possible: the stones and dust of a destroyed Zion still bind the hearts of the faithful who expect restoration.</p>',
    "15": '<p><strong>וְיִירְאוּ גוֹיִם אֶת-שֵׁם יְהוָה וְכָל-מַלְכֵי הָאָרֶץ אֶת-כְּבוֹדֶךָ</strong> (<em>wĕyîrĕʾû gôyim ʾet-shêm yĕhwāh wĕkhol-malkê hāʾāreṣ ʾet-kĕbôdêkā</em>, "The nations will stand in awe of the name of the LORD, and all the kings of the earth will reverence your glory!") — the eschatological scope: Zion\'s restoration is not merely national recovery but the occasion for universal acknowledgment. <em>Yîrĕʾû gôyim</em>: the nations will fear (Ps 67:7; Isa 60:3: "nations will come to your light, and kings to the brightness of your dawn"). The <em>shêm</em> (name) and <em>kābôd</em> (glory) of Ps 96:3 appear again — the missionary goal of the enthronement psalms fulfilled through Zion\'s restoration.</p>',
    "16": '<p><strong>כִּי-בָנָה יְהוָה צִיּוֹן נִרְאָה בִּכְבוֹדוֹ</strong> (<em>kî-bānāh yĕhwāh ṣiyyôn nirʾāh bikhbôdô</em>, "For the LORD will rebuild Zion and reveal himself in his glory!") — <em>bānāh</em>: to build (used for the divine rebuilding of the ruins of exile — Isa 44:26,28; 45:13; Amos 9:11: "I will restore the fallen booth of David"). <em>Nirʾāh bikhbôdô</em>: he will appear in his glory (the <em>niphal</em> of <em>rāʾāh</em>: to be seen/to appear — the divine self-manifestation). The rebuilding of Zion is the occasion of the divine self-disclosure: the construction project is simultaneously a theophany.</p>',
    "17": '<p><strong>פָּנָה אֶל-תְּפִלַּת הָעַרְעָר וְלֹא-בָזָה אֶת-תְּפִלָּתָם</strong> (<em>pānāh ʾel-tĕpillat hāʿărʿār wĕlōʾ-bāzāh ʾet-tĕpillātām</em>, "He listens to the prayer of the destitute and does not despise their prayer!") — <em>ʿărʿār</em>: the destitute/isolated one (from <em>ʿārar</em>: to be stripped bare, to be like a blasted tree in the desert — Jer 17:6: "he will be like a shrub in the desert"). <em>Lōʾ-bāzāh</em>: he did not despise (the negative of <em>bāzāh</em>: to hold in contempt — Ps 22:24: "he has not despised or scorned the suffering of the afflicted one"). The stripped bare, isolated sufferer\'s prayer reaches God; the socially destitute are not beneath divine attention.</p>',
    "18": '<p><strong>תִּכָּתֶב זֹאת לְדוֹר אַחֲרוֹן וְעַם נִבְרָא יְהַלֶּל-יָהּ</strong> (<em>tikkāteb zōʾt lĕdôr ʾaḥărôn wĕʿam nibrāʾ yĕhallel-yāh</em>, "Let this be written for a future generation, so that a people not yet created will praise the LORD!") — <em>tikkāteb</em>: let it be written (the passive imperative — the act of writing this psalm is itself commanded as a future-oriented act). <em>Lĕdôr ʾaḥărôn</em>: for the last/coming generation (not just the next generation but the culminating one — the eschatological community). <em>ʿAm nibrāʾ</em>: a people that will be created/newly born (<em>bārāʾ</em>: the creation verb of Gen 1 applied to a future people who do not yet exist). The Psalmist writes for a community that does not yet exist — the text surviving its author to serve a not-yet-born readership.</p>',
    "19": '<p><strong>כִּי-הִשְׁקִיף מִמְּרוֹם קָדְשׁוֹ יְהוָה מִשָּׁמַיִם אֶל-אֶרֶץ הִבִּיט</strong> (<em>kî-hishqîp mimmĕrôm qōdshô yĕhwāh mishshāmayim ʾel-ʾāreṣ hibbîṭ</em>, "That the LORD looked down from his holy height; from heaven he gazed upon the earth!") — <em>shāqap</em> (hiphil: to look down from a height — Gen 26:8; Num 21:20; Ps 85:11). <em>Mimmĕrôm qōdshô</em>: from his holy height (the exalted position from which the universal sovereign surveys his realm — Isa 57:15: "thus says the One who is high and lifted up, who inhabits eternity, whose name is Holy"). The downward divine gaze from heaven to earth is the movement of divine compassion (Ps 14:2; 33:13-14).</p>',
    "20": '<p><strong>לִשְׁמֹעַ אֶנְקַת אָסִיר לְפַתֵּחַ בְּנֵי תְמוּתָה</strong> (<em>lishĕmōaʿ ʾenqat ʾāsîr lĕpattêaḥ bĕnê tĕmûtāh</em>, "to hear the groaning of the prisoner and release those condemned to death!") — <em>ʾenqat ʾāsîr</em>: the groaning of the prisoner (the gut-sound of the captive with no power of self-liberation — Exod 2:24: "God heard their groaning and remembered his covenant"). <em>Bĕnê tĕmûtāh</em>: the sons of death/those appointed to die (from <em>māwet</em>: death; <em>bĕnê</em>: sons = those belonging to the category of). The divine hearing from the heights (v19) aims specifically at the lowest and most helpless: the prisoner and the death-row occupant.</p>',
    "21": '<p><strong>לְסַפֵּר בְּצִיּוֹן שֵׁם יְהוָה וּתְהִלָּתוֹ בִּירוּשָׁלִָם</strong> (<em>lĕsappêr bĕṣiyyôn shêm yĕhwāh ûtĕhillātô bîrûshālāyim</em>, "so that the name of the LORD would be proclaimed in Zion and his praise sung in Jerusalem!") — the goal of divine rescue: not merely the prisoner\'s liberty but the proclamation of the divine name in Zion. God\'s salvation aim is always simultaneously soteriological (saving the captive) and doxological (praising his name). The circle completes: the individual\'s rescue (vv1-11) leads to Zion\'s restoration (vv13-16) leads to the universal mission (v15) leads to the declaration of praise in Jerusalem (v21).</p>',
    "22": '<p><strong>בְּהִקָּבֵץ עַמִּים יַחְדָּו וּמַמְלָכוֹת לַעֲבֹד אֶת-יְהוָה</strong> (<em>bĕhiqqābêṣ ʿammîm yaḥdāw ûmamlākhôt laʿăbōd ʾet-yĕhwāh</em>, "when peoples and kingdoms assemble together to worship the LORD!") — the culminating vision: <em>ʿammîm yaḥdāw</em> (peoples together — the universal gathering); <em>mamlākhôt</em> (kingdoms — the political structures of the world). <em>Laʿăbōd</em>: to serve/worship (the same verb as Ps 100:2: "serve the LORD with joy"). The individual\'s prayer (vv1-2) has expanded in successive circles to encompass the entire assembly of the world\'s peoples and kingdoms worshipping before YHWH in Zion — the eschatological fulfillment of Isa 2:2-4; 60:3; Rev 21:24-26.</p>',
    "23": '<p><strong>עִנָּה בַדֶּרֶךְ כֹּחִי קִצַּר יָמָי</strong> (<em>ʿinnāh badderek kōḥî qiṣṣar yāmāy</em>, "He has sapped my strength in midcourse; he has shortened my days!") — the psalm returns to the individual speaker\'s crisis. <em>ʿInnāh</em>: to afflict, to humiliate (<em>ʿānāh</em> piel: used of afflicting the poor — Exod 22:21-22; here of God reducing the Psalmist\'s strength). <em>Badderek</em>: in the road/midway (the interruption of the journey before reaching its destination). <em>Qiṣṣar yāmāy</em>: he cut short my days (<em>qāṣar</em>: to be short/harvest; the metaphor of harvest applied to the lifespan — a life cut short before ripening). The transition back from universal hope to personal lament makes the contrast of vv24-28 more dramatic.</p>',
    "24": '<p><strong>אֹמַר אֵלִי אַל-תַּעֲלֵנִי בַּחֲצִי יָמָי</strong> (<em>ʾōmar ʾêlî ʾal-taʿălênî baḥăṣî yāmāy</em>, "I said, \'O my God, do not take me away in the middle of my life!\'") — <em>baḥăṣî yāmāy</em>: in the half of my days (mid-life — Ps 55:23: "men of blood and treachery will not live out half their days"; Isa 38:10: Hezekiah\'s prayer "in the middle of my days I must depart"). The Psalmist prays against a premature death — the life cut short (v23) protests its shortness. <strong>בְּדוֹר דּוֹרִים שְׁנוֹתֶיךָ</strong> (<em>bĕdôr dôrîm shĕnôtêkā</em>, "your years span generation after generation!") — the contrast immediately introduced: God\'s years span the generations while the Psalmist\'s days are cut in half. This contrast prepares the great creation-hymn of vv25-27.</p>',
    "25": '<p><strong>לְפָנִים הָאָרֶץ יָסַדְתָּ וּמַעֲשֵׂה יָדֶיךָ שָׁמָיִם</strong> (<em>lĕpānîm hāʾāreṣ yāsadtā ûmaʿăśêh yādêkā shāmāyim</em>, "Long ago you laid the earth\'s foundation, and the heavens are the work of your hands!") — the beginning of the creation-hymn (vv25-27) that is quoted in Hebrews 1:10-12 and applied by the Father to the Son: the pre-incarnate Christ who laid the earth\'s foundations. <em>Lĕpānîm</em>: formerly, long ago (before the current world order — "in the beginning"). <em>Yāsadtā</em>: you founded/established (the word for laying a foundation — Ps 24:2; 78:69; 89:11; Isa 48:13). <em>Maʿăśêh yādêkā</em>: the work of your hands — the heavens as a divine artifact (Ps 8:3; 19:1). The Psalmist grounds the prayer for life against divine permanence: the Creator of the cosmos is the one the Psalmist appeals to.</p>',
    "26": '<p><strong>הֵמָּה יֹאבֵדוּ וְאַתָּה תַעֲמֹד וְכֻלָּם כַּבֶּגֶד יִבְלוּ</strong> (<em>hêmmāh yōʾbêdû wĕʾattāh taʿămōd wĕkhullām kabbegĕd yiblû</em>, "They will perish, but you will endure; they will all wear out like old clothes!") — the astonishing claim: the heavens and earth (the most permanent things imaginable) will perish (<em>ʾābad</em>) while God stands (<em>ʿāmad</em>). <em>Kabbegĕd yiblû</em>: they will wear out like a garment (the homely image of a worn-out coat — Isa 51:6: "the earth will wear out like a garment"; Isa 50:9: "they will all wear out like a garment"). <strong>כַּלְּבוּשׁ תַּחֲלִיפֵם וְיַחֲלֹפוּ</strong> (<em>kallĕbûsh taḥălîpêm wĕyaḥălōpû</em>, "You will roll them up like a garment and they will be changed!") — <em>ḥālap</em> (hiphil: to change, exchange — as one changes garments). Hebrews 1:12 quotes this phrase of the Son who will fold up the heavens. The cosmos is not permanent — it is a garment God wears and will change.</p>',
    "27": '<p><strong>וְאַתָּה-הוּא וּשְׁנוֹתֶיךָ לֹא יִתָּמּוּ</strong> (<em>wĕʾattāh-hûʾ ûshĕnôtêkā lōʾ yittāmmû</em>, "but you are ever the same, and your years will never end!") — <em>wĕʾattāh-hûʾ</em>: "but you, he is" — the divine self-identification formula (Deut 32:39: "I am He"; Isa 41:4; 43:10,13: "I am He" — the eternal self-consistency of the divine being who cannot change). <em>Shĕnôtêkā lōʾ yittāmmû</em>: your years will not be exhausted/completed (from <em>tāmam</em>: to be completed, to come to an end — used of the completion of Israel\'s suffering in Ps 77:9, but God\'s years never reach completion). Hebrews 1:10-12 applies this entire passage (vv25-27) to the Son, establishing his pre-creational existence and eternal consistency: the same divine nature that the Father ascribes to himself the New Testament ascribes to Christ.</p>',
    "28": '<p><strong>בְּנֵי-עֲבָדֶיךָ יִשְׁכֹּנוּ וְזַרְעָם לְפָנֶיךָ יִכּוֹן</strong> (<em>bĕnê-ʿăbādêkā yishkōnû wĕzarʿām lĕpānêkā yikkôn</em>, "The children of your servants will live in safety; their descendants will be established in your presence!") — the psalm moves from cosmic permanence to covenantal promise. Because God is unchanging (v27), the servants\' children have a foundation. <em>Yishkōnû</em>: they will dwell/inhabit (<em>shākan</em>: the tabernacle-word — to take up residence permanently). <em>Lĕpānêkā yikkôn</em>: before your face they will be established (<em>kônen</em>: firmly set up — the same verb for creation\'s establishment in Ps 96:10). The individual who prayed against premature death (v24) receives the promise that the next generation will be established in the divine presence. The personal lament becomes covenantal hope: the sufferer\'s children are the community of v18 ("a people not yet created who will praise the LORD").</p>',
  },
}


def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 96-102 mkt-original written.')

if __name__ == '__main__':
    main()
